    [Fact]
    public async Task AddAskedQuestion_Should_Persist_Question_Metadata()
    {
        await using var connection = new SqliteConnection("Data Source=:memory:");
        await connection.OpenAsync();

        var options = new DbContextOptionsBuilder<PresaleDataDbContext>()
            .UseSqlite(connection)
            .Options;

        await using var dbContext = new PresaleDataDbContext(options);
        await dbContext.Database.EnsureCreatedAsync();

        var lead = new PresaleLead
        {
            Id = Guid.NewGuid(),
            SessionId = "session-123"
        };

        dbContext.PresaleLeads.Add(lead);
        await dbContext.SaveChangesAsync();

        var repository = new PresaleLeadRepository(dbContext);
        var askedQuestion = new AskedQuestion
        {
            QuestionText = "What challenges do you need help with?",
            Phase = "Discovery",
            AgentName = "discovery_agent",
            QuestionKind = DiscoveryQuestionKind.Initial,
            RoundNumber = 0,
            QuestionTopicKey = "challenge"
        };

        var result = await repository.AddAskedQuestionAsync(lead.Id, askedQuestion);

        Assert.NotNull(result);
        Assert.Equal(lead.Id, result.PresaleLeadId);
        Assert.Equal("What challenges do you need help with?", result.QuestionText);
        Assert.Equal("Discovery", result.Phase);
        Assert.Equal("discovery_agent", result.AgentName);
        Assert.Equal(DiscoveryQuestionKind.Initial, result.QuestionKind);
        Assert.Equal(0, result.RoundNumber);
        Assert.Equal("challenge", result.QuestionTopicKey);
        Assert.True(result.AskedAtUtc <= DateTimeOffset.UtcNow);
    }

