        var question1 = new AskedQuestion
        {
            QuestionText = "First question?",
            Phase = "Discovery",
            AgentName = "discovery_agent",
            QuestionTopicKey = "first-topic",
            AskedAtUtc = DateTimeOffset.UtcNow.AddMinutes(-2)
        };

        var question2 = new AskedQuestion
        {
            QuestionText = "Second question?",
            Phase = "Discovery",
            AgentName = "discovery_agent",
            QuestionTopicKey = "second-topic",
            AskedAtUtc = DateTimeOffset.UtcNow.AddMinutes(-1)
        };

        await repository.AddAskedQuestionAsync(lead.Id, question1);
