        var questions = await repository.GetAskedQuestionsAsync(lead.Id);

        var questionsList = questions.ToList();
        Assert.Equal(2, questionsList.Count);
        Assert.Equal("First question?", questionsList[0].QuestionText);
        Assert.Equal("Second question?", questionsList[1].QuestionText);
    }

