    [Fact]
    public async Task AddAskedQuestionsBatch_Should_Persist_All_Items_Atomically()
    {
        await using var connection = new SqliteConnection("Data Source=:memory:");
        await connection.OpenAsync();

        var options = new DbContextOptionsBuilder<PresaleDataDbContext>()
            .UseSqlite(connection)
            .Options;

        await using var dbContext = new PresaleDataDbContext(options);
        await dbContext.Database.EnsureCreatedAsync();

        var lead = new PresaleLead
        {
            Id = Guid.NewGuid(),
            SessionId = "session-123"
        };

        dbContext.PresaleLeads.Add(lead);
        await dbContext.SaveChangesAsync();

        var repository = new PresaleLeadRepository(dbContext);
        var batch = new List<AskedQuestion>
        {
            new()
            {
                QuestionText = "What challenge are you solving?",
                Phase = "Discovery",
                AgentName = "discovery_agent",
                QuestionKind = DiscoveryQuestionKind.Initial,
                RoundNumber = 0,
                QuestionTopicKey = "challenge"
            },
            new()
            {
                QuestionText = "What timeline do you have?",
                Phase = "Discovery",
                AgentName = "discovery_agent",
                QuestionKind = DiscoveryQuestionKind.Initial,
                RoundNumber = -1,
                QuestionTopicKey = string.Empty
            }
        };

        var result = await repository.AddAskedQuestionsBatchAsync(lead.Id, batch);

        Assert.True(result.Success);
        Assert.Equal(2, result.Questions.Count);

        var persisted = (await repository.GetAskedQuestionsAsync(lead.Id)).ToList();
        Assert.Equal(2, persisted.Count);
        Assert.All(persisted, x => Assert.Equal(lead.Id, x.PresaleLeadId));
        Assert.Contains(persisted, x => x.QuestionTopicKey == "unknown" && x.RoundNumber == 0);
    }

